# Summary stats
statuses = {}
total_cents_by_status = {}
for o in u017_orders:
    s = o['status']
    statuses[s] = statuses.get(s, 0) + 1
    total_cents_by_status[s] = total_cents_by_status.get(s, 0) + o['total_cents']

print('=== ORDER STATUS SUMMARY ===')
for s, c in sorted(statuses.items()):
    print(f'  {s}: {c} orders, total_cents: {total_cents_by_status[s]}')

# Refunded orders detail
print('\n=== REFUNDED ORDERS DETAIL ===')
for o in u017_orders:
    if o['status'] == 'refunded':
        print(json.dumps(o, indent=2))

# Failed orders
print('\n=== FAILED ORDERS ===')
for o in u017_orders:
